import React from 'react';

const AboutMe = () => {
  const items = [
    { label: 'Age', value: '19 years old' },
    { label: 'Hobbies', value: 'Anime, Gym, Games' },
    { label: 'Interest', value: 'Bodybuilding, Kdrama, R&B' },
  ];

  return (
    <section
      id="About-Me"
      className="min-h-screen flex flex-col items-center py-24"
      style={{ background: '#112240', fontFamily: "'Orbitron', sans-serif" }}
    >
      <h1 className="text-4xl text-white mb-12 font-bold">About Me</h1>

      <div className="max-w-3xl w-full flex flex-col gap-6">
        {items.map((item, i) => (
          <div
            key={i}
            className="p-6 rounded-xl"
            style={{
              background: '#f8f9fa',
              borderLeft: '5px solid #0d6efd',
            }}
          >
            <b style={{ color: '#0d6efd' }}>{item.label}:</b>{' '}
            <span style={{ color: '#0b1f3a' }}>{item.value}</span>
          </div>
        ))}
      </div>
    </section>
  );
};

export default AboutMe;
